import type { FeaNode, MarkAttachment } from 'src/lib/openTypeFeatures/feaAst'
import type {
  FeatureEntry,
  LookupFlagIR,
  LookupRecord,
  OpenTypeFeaturesState,
  Rule,
} from 'src/lib/openTypeFeatures/types'
import { getNestedLookupReferences } from 'src/lib/openTypeFeatures/ruleReferences'

const headerComments = [
  'Generated by Kumiko Font Editor.',
  'This file is disposable build output.',
  'It is not guaranteed to match any original feature source imported from a compiled font.',
]

const hasLookupFlags = (flags: LookupFlagIR) =>
  Boolean(
    flags.rightToLeft ||
    flags.ignoreBaseGlyphs ||
    flags.ignoreLigatures ||
    flags.ignoreMarks ||
    flags.useMarkFilteringSet
  )

const mapMarkAttachments = (
  anchors: Record<string, { x: number; y: number }>,
  markClassNameById: Map<string, string>
): MarkAttachment[] =>
  Object.entries(anchors)
    .map(([markClassId, anchor]) => {
      const markClassName = markClassNameById.get(markClassId)
      return markClassName ? { markClassName, anchor } : null
    })
    .filter((entry): entry is MarkAttachment => Boolean(entry))

const missingMarkClassIds = (
  anchors: Record<string, { x: number; y: number }>,
  markClassNameById: Map<string, string>
) =>
  Object.keys(anchors).filter(
    (markClassId) => !markClassNameById.has(markClassId)
  )

const markRuleMissingClassComment = (rule: Rule, missingIds: string[]) => ({
  kind: 'Comment' as const,
  value: `Cannot serialize rule ${rule.id}: missing mark class ${missingIds.join(', ')}`,
})

const markRuleMissingAnchorsComment = (rule: Rule) => ({
  kind: 'Comment' as const,
  value: `Cannot serialize rule ${rule.id}: mark positioning rule has no mark anchors`,
})

const ruleToNode = (
  rule: Rule,
  markClassNameById: Map<string, string>,
  lookupNameById: Map<string, string>
): FeaNode | null => {
  switch (rule.kind) {
    case 'singleSubstitution':
      return {
        kind: 'Substitution',
        ruleId: rule.id,
        pattern: [rule.target],
        replacement: [rule.replacement],
      }
    case 'multipleSubstitution':
      return {
        kind: 'Substitution',
        ruleId: rule.id,
        pattern: [{ kind: 'glyph', glyph: rule.target }],
        replacement: rule.replacement,
      }
    case 'alternateSubstitution':
      return {
        kind: 'Substitution',
        ruleId: rule.id,
        pattern: [{ kind: 'glyph', glyph: rule.target }],
        replacement: [],
        alternates: rule.alternates,
      }
    case 'ligatureSubstitution':
      return {
        kind: 'Substitution',
        ruleId: rule.id,
        pattern: rule.components.map((glyph) => ({ kind: 'glyph', glyph })),
        replacement: [rule.replacement],
      }
    case 'singlePositioning':
      return {
        kind: 'Positioning',
        ruleId: rule.id,
        left: rule.target,
        firstValue: rule.value,
      }
    case 'pairPositioning':
      return {
        kind: 'Positioning',
        ruleId: rule.id,
        left: rule.left,
        right: rule.right,
        firstValue: rule.firstValue,
        secondValue: rule.secondValue,
      }
    case 'contextualSubstitution':
      return {
        kind: 'ContextualSubstitution',
        ruleId: rule.id,
        backtrack: rule.backtrack,
        input: rule.input.map((entry) => ({
          selector: entry.selector,
          lookupNames: (entry.lookupIds ?? [])
            .map((lookupId) => lookupNameById.get(lookupId))
            .filter((name): name is string => Boolean(name)),
        })),
        lookahead: rule.lookahead,
      }
    case 'markToBase': {
      const missingIds = missingMarkClassIds(rule.anchors, markClassNameById)
      if (missingIds.length > 0) {
        return markRuleMissingClassComment(rule, missingIds)
      }
      const marks = mapMarkAttachments(rule.anchors, markClassNameById)
      if (marks.length === 0) {
        return markRuleMissingAnchorsComment(rule)
      }
      return {
        kind: 'MarkToBase',
        ruleId: rule.id,
        base: rule.baseGlyphs,
        marks,
      }
    }
    case 'markToMark': {
      const missingIds = missingMarkClassIds(rule.anchors, markClassNameById)
      if (missingIds.length > 0) {
        return markRuleMissingClassComment(rule, missingIds)
      }
      const marks = mapMarkAttachments(rule.anchors, markClassNameById)
      if (marks.length === 0) {
        return markRuleMissingAnchorsComment(rule)
      }
      return {
        kind: 'MarkToMark',
        ruleId: rule.id,
        baseMark: rule.baseMarks,
        marks,
      }
    }
    case 'markToLigature': {
      const missingIds = rule.componentAnchors.flatMap((componentAnchors) =>
        missingMarkClassIds(componentAnchors, markClassNameById)
      )
      if (missingIds.length > 0) {
        return markRuleMissingClassComment(rule, missingIds)
      }
      const componentMarks = rule.componentAnchors.map((componentAnchors) =>
        mapMarkAttachments(componentAnchors, markClassNameById)
      )
      if (
        componentMarks.length === 0 ||
        componentMarks.some((marks) => marks.length === 0)
      ) {
        return markRuleMissingAnchorsComment(rule)
      }
      return {
        kind: 'MarkToLigature',
        ruleId: rule.id,
        ligature: rule.ligatures,
        componentMarks,
      }
    }
    default:
      return {
        kind: 'Comment',
        value: `Unsupported generated rule kind: ${rule.kind}`,
      }
  }
}

const lookupToBlock = (
  lookup: LookupRecord,
  markClassNameById: Map<string, string>,
  glyphClassNameById: Map<string, string>,
  lookupNameById: Map<string, string>
): FeaNode => {
  const markFilteringSetName = lookup.markFilteringSetClassId
    ? glyphClassNameById.get(lookup.markFilteringSetClassId)
    : undefined
  const missingMarkFilteringSet =
    lookup.lookupFlag.useMarkFilteringSet &&
    lookup.markFilteringSetClassId &&
    !markFilteringSetName
  const serializableLookupFlag = missingMarkFilteringSet
    ? { ...lookup.lookupFlag, useMarkFilteringSet: false }
    : lookup.lookupFlag
  const statements: FeaNode[] = [
    ...(missingMarkFilteringSet
      ? [
          {
            kind: 'Comment' as const,
            value: `Cannot serialize UseMarkFilteringSet for lookup ${lookup.id}: missing glyph class ${lookup.markFilteringSetClassId}`,
          },
        ]
      : []),
    ...(hasLookupFlags(serializableLookupFlag)
      ? [
          {
            kind: 'LookupFlag' as const,
            flags: serializableLookupFlag,
            markFilteringSetName,
          },
        ]
      : []),
    ...lookup.rules
      .map((rule) => ruleToNode(rule, markClassNameById, lookupNameById))
      .filter((node): node is FeaNode => Boolean(node)),
  ]

  return {
    kind: 'LookupBlock',
    name: lookup.name,
    lookupId: lookup.id,
    statements,
  }
}

const featureEntryStatements = (
  entry: FeatureEntry,
  lookupById: Map<string, LookupRecord>
): FeaNode[] => {
  const statements: FeaNode[] = [
    { kind: 'ScriptStatement', script: entry.script },
    { kind: 'LanguageStatement', language: entry.language },
  ]

  for (const lookupId of entry.lookupIds) {
    const lookup = lookupById.get(lookupId)
    if (lookup) {
      statements.push({
        kind: 'Raw',
        value: `  lookup ${lookup.name};`,
      })
    }
  }
  return statements
}

function collectNestedLookupIds(
  lookupId: string,
  lookupById: Map<string, LookupRecord>,
  activeLookupIds: Set<string>
) {
  const lookup = lookupById.get(lookupId)
  if (!lookup) return

  for (const nestedLookupId of lookup.rules.flatMap(
    getNestedLookupReferences
  )) {
    if (activeLookupIds.has(nestedLookupId)) continue
    activeLookupIds.add(nestedLookupId)
    collectNestedLookupIds(nestedLookupId, lookupById, activeLookupIds)
  }
}

export const buildFeaDocument = (state: OpenTypeFeaturesState) => {
  const lookupById = new Map(state.lookups.map((lookup) => [lookup.id, lookup]))
  const lookupNameById = new Map(
    state.lookups.map((lookup) => [lookup.id, lookup.name])
  )
  const glyphClassNameById = new Map(
    state.glyphClasses.map((glyphClass) => [glyphClass.id, glyphClass.name])
  )
  const markClassNameById = new Map(
    state.markClasses.map((markClass) => [markClass.id, markClass.name])
  )
  const activeLookupIds = new Set(
    state.features
      .filter((feature) => feature.isActive)
      .flatMap((feature) => feature.entries.flatMap((entry) => entry.lookupIds))
  )
  for (const lookupId of [...activeLookupIds]) {
    collectNestedLookupIds(lookupId, lookupById, activeLookupIds)
  }

  const statements: FeaNode[] = [
    ...headerComments.map((value) => ({ kind: 'Comment' as const, value })),
    ...(state.rawPrelude
      ? [{ kind: 'Raw' as const, value: state.rawPrelude }]
      : []),
    ...state.languagesystems.map((languageSystem) => ({
      kind: 'LanguageSystem' as const,
      script: languageSystem.script,
      language: languageSystem.language,
    })),
    ...state.glyphClasses.map((glyphClass) => ({
      kind: 'GlyphClass' as const,
      name: glyphClass.name,
      glyphs: glyphClass.glyphs,
      classId: glyphClass.id,
    })),
    ...state.markClasses.flatMap((markClass) =>
      markClass.marks.map((mark) => ({
        kind: 'MarkClass' as const,
        glyph: mark.glyph,
        anchor: mark.anchor,
        className: markClass.name,
      }))
    ),
    ...state.lookups
      .filter((lookup) => activeLookupIds.has(lookup.id))
      .map((lookup) =>
        lookupToBlock(
          lookup,
          markClassNameById,
          glyphClassNameById,
          lookupNameById
        )
      ),
    ...state.features
      .filter((feature) => feature.isActive)
      .map((feature) => ({
        kind: 'FeatureBlock' as const,
        tag: feature.tag,
        featureId: feature.id,
        statements: feature.entries.flatMap((entry) =>
          featureEntryStatements(entry, lookupById)
        ),
      })),
  ]

  return {
    kind: 'Document' as const,
    statements,
  }
}
